import{_ as n,c as i,o as t,a1 as r}from"./chunks/framework.DILC4Csi.js";const f=JSON.parse('{"title":"Anhang: Konfigurationsreferenz und Migration | oh-my-opencode","description":"Erfahren Sie mehr über die Konfigurationsreferenz von oh-my-opencode, den Claude Code-Kompatibilitätsleitfaden und die Verwendung der integrierten MCP-Server. Verstehen Sie Konfigurationsoptionen, Migrationsschritte und die Konfiguration von Suchfunktionen für eine nahtlose Migration von Claude Code.","frontmatter":{"title":"Anhang: Konfigurationsreferenz und Migration | oh-my-opencode","sidebarTitle":"Konfigurationsmigration einfach gelöst","subtitle":"Anhang: Konfigurationsreferenz und Migration","description":"Erfahren Sie mehr über die Konfigurationsreferenz von oh-my-opencode, den Claude Code-Kompatibilitätsleitfaden und die Verwendung der integrierten MCP-Server. Verstehen Sie Konfigurationsoptionen, Migrationsschritte und die Konfiguration von Suchfunktionen für eine nahtlose Migration von Claude Code.","tags":["Anhang","Referenz"],"order":170},"headers":[],"relativePath":"de/code-yeongyu/oh-my-opencode/appendix/index.md","filePath":"de/code-yeongyu/oh-my-opencode/appendix/index.md"}'),a={name:"de/code-yeongyu/oh-my-opencode/appendix/index.md"};function o(s,e,d,l,h,u){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="anhang-referenzmaterial-und-kompatibilitatsleitfaden" tabindex="-1">Anhang: Referenzmaterial und Kompatibilitätsleitfaden <a class="header-anchor" href="#anhang-referenzmaterial-und-kompatibilitatsleitfaden" aria-label="Permalink to &quot;Anhang: Referenzmaterial und Kompatibilitätsleitfaden&quot;">​</a></h1><p>Dieses Kapitel enthält detaillierte Referenzmaterialien und Kompatibilitätsleitfäden für <strong>oh-my-opencode</strong>, einschließlich vollständiger Konfigurationsbeschreibungen, Claude Code-Migrationsunterstützung und detaillierten Einführungen in die integrierten Erweiterungsserver.</p><h2 id="kapitelinhalt" tabindex="-1">Kapitelinhalt <a class="header-anchor" href="#kapitelinhalt" aria-label="Permalink to &quot;Kapitelinhalt&quot;">​</a></h2><p>Dieses Kapitel enthält drei wichtige Abschnitte:</p><table tabindex="0"><thead><tr><th>Unterseite</th><th>Beschreibung</th><th>Schwierigkeit</th></tr></thead><tbody><tr><td><a href="./claude-code-compatibility/">Claude Code-Kompatibilität</a></td><td>Vollständiger Leitfaden für die Migration von Claude Code zu OpenCode, einschließlich Kompatibilitätsmechanismen für Commands, Skills, Agents, MCPs und Hooks</td><td>⭐⭐</td></tr><tr><td><a href="./configuration-reference/">Konfigurationsreferenz</a></td><td>Vollständige Schema-Beschreibung der oh-my-opencode-Konfigurationsdatei, einschließlich aller Felder, Typen und Standardwerte</td><td>⭐⭐⭐</td></tr><tr><td><a href="./builtin-mcps/">Integrierte MCPs</a></td><td>Funktionen und Verwendungsmethoden der 3 integrierten MCP-Server (Exa Websearch, Context7, Grep.app)</td><td>⭐⭐</td></tr></tbody></table><h2 id="empfohlener-lernpfad" tabindex="-1">Empfohlener Lernpfad <a class="header-anchor" href="#empfohlener-lernpfad" aria-label="Permalink to &quot;Empfohlener Lernpfad&quot;">​</a></h2><p>Wählen Sie die Lernreihenfolge basierend auf Ihren Anforderungen:</p><h3 id="pfad-1-migration-von-claude-code" tabindex="-1">Pfad 1: Migration von Claude Code <a class="header-anchor" href="#pfad-1-migration-von-claude-code" aria-label="Permalink to &quot;Pfad 1: Migration von Claude Code&quot;">​</a></h3><p>Wenn Sie ein Benutzer sind, der von Claude Code migriert:</p><ol><li>Lesen Sie zuerst <strong><a href="./claude-code-compatibility/">Claude Code-Kompatibilität</a></strong>, um zu erfahren, wie Sie Ihre vorhandene Konfiguration nahtlos migrieren können</li><li>Sehen Sie sich dann <strong><a href="./configuration-reference/">Konfigurationsreferenz</a></strong> an, um die verfügbaren Konfigurationsoptionen besser zu verstehen</li><li>Lernen Sie schließlich <strong><a href="./builtin-mcps/">Integrierte MCPs</a></strong>, um zu erfahren, wie Sie zusätzliche Suchfunktionen konfigurieren können</li></ol><h3 id="pfad-2-tiefgreifende-konfigurationsanpassung" tabindex="-1">Pfad 2: Tiefgreifende Konfigurationsanpassung <a class="header-anchor" href="#pfad-2-tiefgreifende-konfigurationsanpassung" aria-label="Permalink to &quot;Pfad 2: Tiefgreifende Konfigurationsanpassung&quot;">​</a></h3><p>Wenn Sie das Verhalten von oh-my-opencode tiefgreifend anpassen möchten:</p><ol><li>Beginnen Sie mit <strong><a href="./configuration-reference/">Konfigurationsreferenz</a></strong>, um alle konfigurierbaren Elemente zu verstehen</li><li>Lernen Sie <strong><a href="./builtin-mcps/">Integrierte MCPs</a></strong>, um Such- und Dokumentabfragefunktionen zu konfigurieren</li><li>Sehen Sie sich <strong><a href="./claude-code-compatibility/">Claude Code-Kompatibilität</a></strong> an, um die Konfigurationsoptionen der Kompatibilitätsschicht zu verstehen</li></ol><h3 id="pfad-3-schnelle-referenz" tabindex="-1">Pfad 3: Schnelle Referenz <a class="header-anchor" href="#pfad-3-schnelle-referenz" aria-label="Permalink to &quot;Pfad 3: Schnelle Referenz&quot;">​</a></h3><p>Wenn Sie nur bestimmte Informationen nachschlagen müssen:</p><ul><li><strong>Konfigurationsfragen</strong> → Sehen Sie sich direkt <strong><a href="./configuration-reference/">Konfigurationsreferenz</a></strong> an</li><li><strong>Migrationsfragen</strong> → Sehen Sie sich direkt <strong><a href="./claude-code-compatibility/">Claude Code-Kompatibilität</a></strong> an</li><li><strong>MCP-Konfiguration</strong> → Sehen Sie sich direkt <strong><a href="./builtin-mcps/">Integrierte MCPs</a></strong> an</li></ul><h2 id="voraussetzungen" tabindex="-1">Voraussetzungen <a class="header-anchor" href="#voraussetzungen" aria-label="Permalink to &quot;Voraussetzungen&quot;">​</a></h2><p>Es wird empfohlen, dass Sie vor dem Studium dieses Kapitels bereits:</p><ul><li>✅ <strong><a href="./../start/installation/">Installation und Konfiguration</a></strong> abgeschlossen haben</li><li>✅ Die Grundkonzepte des <strong><a href="./../start/sisyphus-orchestrator/">Sisyphus-Orchestrators</a></strong> verstanden haben</li><li>✅ Mit der Bearbeitung von JSON-Konfigurationsdateien vertraut sind</li></ul><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Nach Abschluss dieses Kapitels können Sie:</p><ul><li>🚀 <strong><a href="./../advanced/">Erweiterte Funktionen</a></strong> ausprobieren, um mehr fortgeschrittene Verwendungsmöglichkeiten zu lernen</li><li>🔧 <strong><a href="./../faq/">Häufig gestellte Fragen</a></strong> ansehen, um Probleme bei der Verwendung zu lösen</li><li>📖 <strong><a href="./../changelog/">Änderungsprotokoll</a></strong> lesen, um die neuesten Funktionsverbesserungen zu erfahren</li></ul><div class="tip custom-block"><p class="custom-block-title">Hinweis</p><p>Der Inhalt dieses Kapitels dient hauptsächlich als Referenzmaterial und muss nicht in der angegebenen Reihenfolge gelesen werden. Sie können jederzeit den entsprechenden Abschnitt nach Bedarf nachschlagen.</p></div>',23)])])}const c=n(a,[["render",o]]);export{f as __pageData,c as default};
